class ApiClient {
  static const String baseUrl = 'https://api.example.com';
  String? _authToken;
  
  final http.Client _client = http.Client();

  Map<String, String> _getHeaders() {
    final headers = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };
    
    if (_authToken != null) {
      headers['Authorization'] = 'Bearer $_authToken';
    }
    
    return headers;
  }

  Future<Map<String, dynamic>> authenticate(String username, String password) async {
    try {
      final response = await _client.post(
        Uri.parse('$baseUrl/auth/login'),
        headers: _getHeaders(),
        body: jsonEncode({
          'username': username,
          'password': password,
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        _authToken = data['token'] as String?;
        return {'success': true, 'data': data};
      } else {
        return {
          'success': false,
          'error': 'Authentication failed: ${response.statusCode}'
        };
      }
    } on SocketException {
      return {'success': false, 'error': 'No internet connection'};
    } on HttpException {
      return {'success': false, 'error': 'HTTP error occurred'};
    } on FormatException {
      return {'success': false, 'error': 'Invalid response format'};
    } catch (e) {
      return {'success': false, 'error': 'Unexpected error: $e'};
    }
  }

  Future<Map<String, dynamic>> getUserProfile() async {
    if (_authToken == null) {
      return {'success': false, 'error': 'Not authenticated'};
    }

    try {
      final response = await _client.get(
        Uri.parse('$baseUrl/user/profile'),
        headers: _getHeaders(),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        return {'success': true, 'data': data};
      } else if (response.statusCode == 401) {
        _authToken = null;
        return {'success': false, 'error': 'Unauthorized'};
      } else {
        return {
          'success': false,
          'error': 'Failed to fetch profile: ${response.statusCode}'
        };
      }
    } on SocketException {
      return {'success': false, 'error': 'No internet connection'};
    } on HttpException {
      return {'success': false, 'error': 'HTTP error occurred'};
    } on FormatException {
      return {'success': false, 'error': 'Invalid response format'};
    } catch (e) {
      return {'success': false, 'error': 'Unexpected error: $e'};
    }
  }

  Future<Map<String, dynamic>> syncData(Map<String, dynamic> localData) async {
    if (_authToken == null) {
      return {'success': false, 'error': 'Not authenticated'};
    }

    try {
      final response = await _client.post(
        Uri.parse('$baseUrl/sync'),
        headers: _getHeaders(),
        body: jsonEncode(localData),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        return {'success': true, 'data': data};
      } else if (response.statusCode == 401) {
        _authToken = null;
        return {'success': false, 'error': 'Unauthorized'};
      } else {
        return {
          'success': false,
          'error': 'Sync failed: ${response.statusCode}'
        };
      }
    } on SocketException {
      return {'success': false, 'error': 'No internet connection'};
    } on HttpException {
      return {'success': false, 'error': 'HTTP error occurred'};
    } on FormatException {
      return {'success': false, 'error': 'Invalid response format'};
    } catch (e) {
      return {'success': false, 'error': 'Unexpected error: $e'};
    }
  }

  void logout() {
    _authToken = null;
  }

  bool get isAuthenticated => _authToken != null;

  void dispose() {
    _client.close();
  }
}

